using Microsoft.Extensions.Logging;
using SkiaSharp.Views.Maui.Controls.Hosting;

namespace Repro;

public static class MauiProgram
{
    public static MauiApp CreateMauiApp()
    {
        var builder = MauiApp.CreateBuilder();
        builder.UseMauiApp<App>().UseSkiaSharp();
        return builder.Build();
    }
}

using SkiaSharp; using SkiaSharp.Views.Maui;
namespace Repro;
public partial class MainPage : ContentPage
{
    int frameCount = 0;
    readonly DateTime startTime = DateTime.UtcNow;
    public MainPage() { InitializeComponent(); }
    private void OnPaintSurface(object? sender, SKPaintGLSurfaceEventArgs e)
    {
        frameCount++;
        var canvas = e.Surface.Canvas;
        canvas.Clear(SKColors.DarkBlue);
        using var linePaint = new SKPaint { Color = SKColors.Yellow, StrokeWidth = 2, IsAntialias = true, Style = SKPaintStyle.Stroke };
        for (int i = 0; i < 30; i++)
            canvas.DrawLine((float)(Math.Sin(frameCount*0.01+i)*e.Info.Width*0.4+e.Info.Width*0.5), (float)(Math.Cos(frameCount*0.01+i)*e.Info.Height*0.4+e.Info.Height*0.5), (float)(Math.Cos(frameCount*0.02+i*0.5)*e.Info.Width*0.3+e.Info.Width*0.5), (float)(Math.Sin(frameCount*0.02+i*0.5)*e.Info.Height*0.3+e.Info.Height*0.5), linePaint);
        using var circlePaint = new SKPaint { Color = SKColors.Red, StrokeWidth = 2, IsAntialias = true, Style = SKPaintStyle.Stroke };
        for (int i = 0; i < 30; i++)
            canvas.DrawCircle((float)(Math.Sin(frameCount*0.015+i*0.3)*e.Info.Width*0.35+e.Info.Width*0.5), (float)(Math.Cos(frameCount*0.015+i*0.3)*e.Info.Height*0.35+e.Info.Height*0.5), 10+(i%10)*5, circlePaint);
        canvas.Flush();
        if (frameCount % 60 == 0) Console.WriteLine($"[REPRO] Frame={frameCount} FPS={frameCount/(DateTime.UtcNow-startTime).TotalSeconds:F1} ManagedMem={GC.GetTotalMemory(false)/1048576.0:F1}MB");
    }
}
